import logging
import azure.functions as func
from azure.storage.blob import BlobServiceClient

def main(req: func.HttpRequest) -> func.HttpResponse:
    logging.info('HTTP trigger function processed a request.')
    
    blob_path = req.params.get('blob_path')
    if not blob_path:
        return func.HttpResponse("Please pass a blob_path in the query string", status_code=400)
    
    try:
        connection_string = "your_connection_string_here"
        blob_service_client = BlobServiceClient.from_connection_string(connection_string)
        blob_client = blob_service_client.get_blob_client(container="your_container_name", blob=blob_path)

        blob_data = blob_client.download_blob()
        file_content = blob_data.readall()

        return func.HttpResponse(file_content, mimetype="application/octet-stream")
    except Exception as e:
        logging.error(f"Error occurred: {str(e)}")
        return func.HttpResponse(f"Failed to read the blob: {str(e)}", status_code=500)